import React, { useState } from 'react';
import './calc.css';
function Calc() {
  const [monitorText,setMonitorText] = useState('');

  const handleClick = (event) => {
    setMonitorText(event.target.textContent);
  }

  // const Plus = () => {
  //   setNumber(number + 1);
  // }

  // const onDecrease = () => {
  //   setNumber(number - 1);
  // }

  return (
    <div className='wrap'>
      <div className='calc'>
        <div className='monitor'>{monitorText}</div>
        <div className='calc-button'>
          <button onClick={handleClick}>9</button>
          <button onClick={handleClick}>8</button>
          <button onClick={handleClick}>7</button>
          <button>➕</button>

          <button onClick={handleClick}>6</button>
          <button onClick={handleClick}>5</button>
          <button onClick={handleClick}>4</button>
          <button>➖</button>
          <button onClick={handleClick}>3</button>
          <button onClick={handleClick}>2</button>
          <button onClick={handleClick}>1</button>
          <button>✖️</button>
          <button className='btn-zero' onClick={handleClick}>0</button>
          <button>.</button>
          <button>➗</button>
          <button>🔙</button>
          <button>DEL</button>
          <button className='btn-result'>🟰</button>
        </div>
      </div>
    </div>
  );
}

export default Calc;
